mapper.insert:

    SELECT NEXTVAL('PR_DISP_CTG_BASE_SQ01') AS dispCtgNo

/* DisplayCategoryCommandMyBatisDao.insertPrDispCtgBase */
INSERT INTO PR_DISP_CTG_BASE (
    DISP_CTG_NO
    , SITE_NO
    , DPML_NO
    , DISP_SEQ
    , USE_YN
    , UPR_DISP_CTG_NO
    , LRG_CTG_NO
    , MID_CTG_NO
    , SML_CTG_NO
    , THN_CTG_NO
    , LEAF_YN
    , SYS_REG_ID
    , SYS_REG_DTM
    , SYS_MOD_ID
    , SYS_MOD_DTM
) VALUES (
    #{dispCtgNo}
    , #{siteNo}
    , #{dpmlNo}
    , #{dispSeq}
    , #{useYn}
    , #{uprDispCtgNo}
    , #{lrgCtgNo}
    , #{midCtgNo}
    , #{smlCtgNo}
    , #{thnCtgNo}
    , #{leafYn}
    , #{sysRegId}
    , NOW()
    , #{sysModId}
    , NOW()
)

mapper.update:
/* DisplayCategoryCommandMyBatisDao.updatePrDispCtgBaseDispCtgNo */
UPDATE PR_DISP_CTG_BASE
SET
    LRG_CTG_NO = #{lrgCtgNo}
    , MID_CTG_NO = #{midCtgNo}
    , SML_CTG_NO = #{smlCtgNo}
    , THN_CTG_NO = #{thnCtgNo}
    , SYS_MOD_ID = #{sysModId}
    , SYS_MOD_DTM = NOW()
WHERE DISP_CTG_NO = #{dispCtgNo}

update.foreach:
UPDATE PR_DISP_CTG_BASE
SET
    LRG_CTG_NO = #{item.lrgCtgNo}
    , MID_CTG_NO = #{item.midCtgNo}
    , SML_CTG_NO = #{item.smlCtgNo}
    , THN_CTG_NO = #{item.thnCtgNo}
    , SYS_MOD_ID = #{item.sysModId}
    , SYS_MOD_DTM = NOW()
WHERE DISP_CTG_NO = #{item.dispCtgNo}

