/* DisplayCategoryCommandMyBatisDao.insertPrDispCtgBaseMl */
INSERT INTO PR_DISP_CTG_BASE_ML (
    DISP_CTG_NO
    , DISP_CTG_NM
    , LANG_CD
    , SYS_REG_ID
    , SYS_REG_DTM
    , SYS_MOD_ID
    , SYS_MOD_DTM
) VALUES (
    #{dispCtgNo}
    , #{dispCtgNm}
    , #{langCd}
    , #{sysRegId}
    , NOW()
    , #{sysModId}
    , NOW()
)
ON CONFLICT (DISP_CTG_NO, LANG_CD)
DO UPDATE SET
    DISP_CTG_NM = EXCLUDED.DISP_CTG_NM
    , SYS_MOD_ID = EXCLUDED.SYS_MOD_ID
    , SYS_MOD_DTM = NOW()

